// Compute weekly statistics
const user = $('Per User').item.json;
const logs = $('Get 7-Day Logs').all().map(i => i.json);
const events = $('Get Feature Events').all().map(i => i.json);

if (logs.length === 0) {
  return [{ json: { skip: true, userId: user.id, telegramId: user.telegram_id } }];
}

// Core stats
const daysLogged = logs.length;
const avgCalories = Math.round(logs.reduce((s, d) => s + (d.calories_consumed || 0), 0) / daysLogged);
const avgSleep = (logs.reduce((s, d) => s + (parseFloat(d.sleep_hours) || 0), 0) / daysLogged).toFixed(1);
const avgEnergy = (logs.reduce((s, d) => s + (d.energy_level || 0), 0) / daysLogged).toFixed(1);
const avgSteps = Math.round(logs.reduce((s, d) => s + (d.steps || 0), 0) / daysLogged);
const workoutDays = logs.filter(d => d.workout_done).length;
const calorieTarget = user.daily_calorie_target || 2000;
const onTargetDays = logs.filter(d => {
  const cal = d.calories_consumed || 0;
  return cal >= calorieTarget * 0.85 && cal <= calorieTarget * 1.15;
}).length;
const adherencePct = Math.round((onTargetDays / daysLogged) * 100);

// Feature activity summary
const featureActivity = {};
events.forEach(e => {
  if (!featureActivity[e.feature_id]) featureActivity[e.feature_id] = 0;
  featureActivity[e.feature_id]++;
});

// Chart data arrays for QuickChart
const chartLabels = logs.map(d => d.log_date).reverse();
const calorieData = logs.map(d => d.calories_consumed || 0).reverse();
const targetData = logs.map(() => calorieTarget).reverse();
const sleepData = logs.map(d => parseFloat(d.sleep_hours) || 0).reverse();
const energyData = logs.map(d => d.energy_level || 0).reverse();

// Calorie chart config
const calorieChartConfig = {
  type: 'bar',
  data: {
    labels: chartLabels,
    datasets: [
      { label: 'Calories', data: calorieData, backgroundColor: 'rgba(99,179,237,0.8)', borderColor: 'rgba(66,153,225,1)', borderWidth: 1 },
      { label: 'Target', data: targetData, type: 'line', borderColor: 'rgba(245,101,101,0.8)', borderWidth: 2, fill: false, pointRadius: 0 }
    ]
  },
  options: {
    title: { display: true, text: 'Daily Calories vs Target' },
    scales: { yAxes: [{ ticks: { beginAtZero: true } }] }
  }
};

// Sleep/Energy chart config
const sleepEnergyChartConfig = {
  type: 'line',
  data: {
    labels: chartLabels,
    datasets: [
      { label: 'Sleep (hrs)', data: sleepData, borderColor: 'rgba(154,117,234,0.9)', borderWidth: 2, fill: false },
      { label: 'Energy (/10)', data: energyData, borderColor: 'rgba(72,187,120,0.9)', borderWidth: 2, fill: false }
    ]
  },
  options: { title: { display: true, text: 'Sleep & Energy Trend' } }
};

return [{ json: {
  skip: false,
  userId: user.id,
  telegramId: user.telegram_id,
  firstName: user.first_name,
  goal: user.goal,
  daysLogged,
  avgCalories,
  avgSleep,
  avgEnergy,
  avgSteps,
  workoutDays,
  adherencePct,
  featureActivity,
  calorieChartConfig: encodeURIComponent(JSON.stringify(calorieChartConfig)),
  sleepEnergyChartConfig: encodeURIComponent(JSON.stringify(sleepEnergyChartConfig))
} }];

